      "2": {
        "text": "പരമാധികാരിയും സത്യവുമായ അള്ളാഹു [എല്ലാറ്റിനുമുപരിയായി] അത്രയും ഉന്നതനാണ്. നിങ്ങൾക്ക് ഖുർആൻ അവതരണം പൂർത്തിയാകുന്നതിന് മുമ്പ് അത് പാരായണം ചെയ്യുന്നതിൽ ധൃതിപ്പെടരുത്. എൻറെ രക്ഷിതാവേ, എനിക്ക് അറിവ് വർദ്ധിപ്പിക്കേണമേ എന്ന് പറയുകയും ചെയ്യരുത്.",
        "sura": "താ-ഹ",
        "verse_number": "114"
      },
      "3": {
        "text": "തീർച്ചയായും, എല്ലാ പ്രയാസങ്ങൾക്കും ഒപ്പം ആശ്വാസമുണ്ട്.",
        "sura": "അൽ-ഷാർ",
        "verse_number": "6"
      },
      "4": {
        "text": "അതിനാൽ ക്ഷമയോടെയിരിക്കുക. തീർച്ചയായും അല്ലാഹുവിൻ്റെ വാഗ്ദാനം സത്യമാണ്. [വിശ്വാസത്തിൽ] ഉറപ്പില്ലാത്ത നിങ്ങളെ അവർ അസ്വസ്ഥരാക്കാതിരിക്കട്ടെ.",
        "sura": "അൽ-റം",
        "verse_number": "60"
      },
      "5": {
        "text": "ഒരു ആത്മാവിനെ അതിൻ്റെ കഴിവിനനുസരിച്ചല്ലാതെ അല്ലാഹു ചുമത്തുകയില്ല. അതിന് അത് സമ്പാദിച്ചതിൻ്റെ ഫലം ഉണ്ടായിരിക്കും, അത് സമ്പാദിച്ചതിൻ്റെ ഫലം വഹിക്കുകയും ചെയ്യും. \"ഞങ്ങളുടെ നാഥാ, ഞങ്ങൾ മറക്കുകയോ തെറ്റ് ചെയ്യുകയോ ചെയ്‌തിട്ടുണ്ടെങ്കിൽ ഞങ്ങളുടെ മേൽ കുറ്റം ചുമത്തരുതേ. ഞങ്ങളുടെ നാഥാ, ഞങ്ങളുടെ മുമ്പുള്ളവരുടെ മേൽ നീ ചുമത്തിയതുപോലുള്ള ഒരു ഭാരം ഞങ്ങളുടെ മേൽ ചുമത്തരുതേ. ഞങ്ങളുടെ നാഥാ, ഞങ്ങൾക്ക് താങ്ങാൻ കഴ���വില്ലാത്തത് ഞങ്ങളുടെ മേൽ ചുമത്തരുതേ. ഞങ്ങളോട് ക്ഷമിക്കൂ, ഞങ്ങളോട് ക്ഷമിക്കൂ, ഞങ്ങളോട് കരുണ കാണിക്കേണമേ.",
        "sura": "അൽ-ബഖറ",
        "verse_number": "286"
      },
      "6": {
        "text": "നമുക്കുവേണ്ടി പരിശ്രമിക്കുന്നവരെ - തീർച്ചയായും നാം അവരെ നമ്മുടെ വഴികളിലേക്ക് നയിക്കും. തീർച്ചയായും അല്ലാഹു നന്മ ചെയ്യുന്നവരോടൊപ്പമാണ്.",
        "sura": "അൽ-അങ്കബട്ട്",
        "verse_number": "69"
      },
      "7": {
        "text": "അവൻ പ്രതീക്ഷിക്കാത്ത ഇടങ്ങളിൽ നിന്ന് അവന് അവന് ഉപജീവനം നൽകും. വല്ലവനും അല്ലാഹുവിൽ ഭരമേൽപിക്കുന്ന പക്ഷം അവന്ന് അവൻ തന്നെ മതി. തീർച്ചയായും അല്ലാഹു അവൻ്റെ ഉദ്ദേശ്യം നിറവേറ്റും. എല്ലാത്തിനും അല്ലാഹു ഒരു പരിധി നിശ്ചയിച്ചിട്ടുണ്ട്.",
        "sura": "അൽ-തലാഖ്",
        "verse_number": "3"
      },
      "8": {
        "text": "നിങ്ങളുടെ രക്ഷിതാവ് ഇപ്രകാരം പ്രഖ്യാപിച്ച സന്ദർഭം (ഓർക്കുക) നിങ്ങൾ നന്ദിയുള്ളവരാണെങ്കിൽ തീർച്ചയായും ഞാൻ നിങ്ങൾക്ക് (അനുകൂലമായി) വർദ്ധിപ്പിക്കും. നിങ്ങൾ നിഷേധിക്കുകയാണെങ്കിൽ തീർച്ചയായും എൻ്റെ ശിക്ഷ കഠിനമായിരിക്കും.",
        "sura": "ഇബ്രാഹിം",
        "verse_number": "7"
      }
